const message = $json.message ?? {};
const from = message.from ?? {};
const chat = message.chat ?? {};
const text = typeof message.text === 'string' ? message.text.trim() : '';
const normalized = text.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

function hasAny(values) {
  return values.some((value) => normalized.includes(value));
}

function isGreetingOnly() {
  return ['oi', 'ola', 'bom dia', 'boa tarde', 'boa noite'].includes(normalized);
}

function isStartCommand() {
  return normalized === '/start' || normalized.startsWith('/start ');
}

function looksTrainingRelated() {
  return hasAny([
    'treino', 'treinar', 'exercicio', 'exercicios', 'serie', 'series', 'repeticao', 'repeticoes',
    'academia', 'musculo', 'musculos', 'hipertrofia', 'forca', 'cardio', 'aquecimento', 'alongamento',
    'supino', 'agachamento', 'leg press', 'remada', 'puxada', 'desenvolvimento', 'rosca', 'triceps',
    'prancha', 'esteira', 'bicicleta', 'panturrilha', 'posterior', 'peito', 'costas', 'perna', 'ombro'
  ]);
}

function looksExecutionQuestion() {
  return hasAny([
    'como fazer', 'forma de fazer', 'melhor forma', 'execucao', 'executar', 'postura', 'tecnica',
    'movimento', 'amplitude', 'pegada', 'posicao', 'puxar', 'empurrar', 'subir', 'descer'
  ]);
}

function looksWorkoutStructureRequest() {
  return hasAny(['monta', 'montar', 'organizar', 'dividir', 'estrutura', 'rotina', 'ficha', 'planejar']);
}

function looksTrainingVariableQuestion() {
  return hasAny(['quantas series', 'quantas repeticoes', 'repeticoes', 'volume', 'frequencia', 'intensidade', 'cadencia']);
}

function hasRiskSignal() {
  return hasAny(['dor', 'doendo', 'machuquei', 'machucado', 'lesao', 'fisgada', 'formigamento', 'tontura', 'piorando']);
}

function hasStopRiskSignal() {
  return hasAny(['dor forte', 'dor aguda', 'fisgada', 'formigamento', 'dor no peito', 'tontura', 'piorando']);
}

async function classifyWithLlm() {
  const allowedIntents = [
    'short_workout', 'rest_question', 'failure_question', 'substitution', 'exercise_execution',
    'workout_request', 'training_variable_question', 'concept_explanation', 'personalized_workout_request',
    'exact_load', 'out_of_scope', 'fallback'
  ];
  const allowedMacroIntents = [
    'training_help', 'exercise_change', 'exercise_execution', 'workout_structure', 'training_variable',
    'meta_or_feedback', 'out_of_scope', 'unknown'
  ];
  const system = `Classifique uma mensagem de usuario para o Gym Buddy. Responda somente JSON valido, sem markdown. Nao gere resposta ao usuario. Intents permitidas: ${allowedIntents.join(', ')}. Macro-intents permitidas: ${allowedMacroIntents.join(', ')}. Use risk_level normal salvo se a mensagem falar explicitamente de dor, lesao, fisgada, formigamento, tontura ou piora. Se a mensagem pedir kg exato, use exact_load. Se a mensagem for sobre tecnica, postura, pegada, amplitude ou como fazer um exercicio, use exercise_execution. Se for fora de treino, use out_of_scope.`;
  const user = `Mensagem: ${text}\n\nRetorne JSON com: intent, macro_intent, confidence (high|medium|low), risk_level (normal|caution|stop), needs_clarification (boolean).`;

  try {
    const response = await fetch('http://ollama:11434/api/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'llama3.2:3b',
        stream: false,
        format: 'json',
        options: { temperature: 0, num_predict: 160 },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user }
        ]
      })
    });
    const raw = await response.text();
    const parsed = raw ? JSON.parse(raw) : {};
    const content = parsed.message?.content ?? parsed.response ?? '';
    const result = typeof content === 'string' ? JSON.parse(content) : content;
    const intent = allowedIntents.includes(result.intent) ? result.intent : 'fallback';
    const macro = allowedMacroIntents.includes(result.macro_intent) ? result.macro_intent : 'unknown';
    const confidence = ['high', 'medium', 'low'].includes(result.confidence) ? result.confidence : 'low';
    const risk = ['normal', 'caution', 'stop'].includes(result.risk_level) ? result.risk_level : 'normal';
    return {
      status: response.ok ? 'success' : 'error',
      intent,
      macro_intent: macro,
      confidence,
      risk_level: risk,
      needs_clarification: Boolean(result.needs_clarification),
      error: response.ok ? null : (parsed.error || response.statusText || 'classifier_failed')
    };
  } catch (error) {
    return {
      status: 'error',
      intent: 'fallback',
      macro_intent: 'unknown',
      confidence: 'low',
      risk_level: 'normal',
      needs_clarification: true,
      error: error.message || 'classifier_failed'
    };
  }
}

const cards = {
  rest: `CARD: Rest Intervals\n- Short rests can work for lighter or isolation exercises.\n- Longer rests help preserve performance in heavier compound exercises.\n- Practical range: 1-2 min for lighter work, 2-3 min for heavier compound work.\n- If technique or performance drops sharply, rest longer.\n- Do not prescribe an exact interval as individualized programming.`,
  failure: `CARD: Failure Training\n- Failure means another good repetition is unlikely.\n- RIR means repetitions in reserve; RIR 2 means about 2 good reps left.\n- Most sets do not need to be taken to failure.\n- Many useful sets can end with 1-3 RIR.\n- Failure can increase fatigue and technique breakdown.`,
  shortWorkout: `CARD: Short Workouts\n- Keep it simple and general, not deeply personalized.\n- Include a short warm-up with esteira, bicicleta or mobilidade leve. Do not use prancha as warm-up.\n- Prefer 4-6 exercises using broad patterns: lower body, push, pull, hinge or hamstring, core.\n- Use common gym exercises only: leg press, agachamento, supino, flexao, puxada, remada, desenvolvimento, mesa flexora, cadeira extensora, terra romeno, prancha, bicicleta ou esteira.\n- Do not invent exercise names. If unsure, choose leg press, supino, remada, mesa flexora and prancha.\n- For strength exercises, use sets and reps. Use seconds only for prancha, cardio or warm-up.\n- Preferred 30 min structure: 5 min warm-up; leg press 3x8-12; supino or flexao 3x8-12; remada 3x8-12; mesa flexora 2x10-12; prancha 2x30-45s; rest 60-90s.\n- Do not promise results or prescribe exact loads.\n- Tell the user to stop or adapt if pain appears.`,
  substitution: `CARD: Exercise Substitutions\n- A substitution can be reasonable when goal, equipment and comfort are compatible.\n- Similar exercises are not identical.\n- Consider the reason: equipment, preference, pain, difficulty or time.\n- If pain is the reason, apply safety boundaries and do not treat it as a normal swap.`,
  load: `CARD: Load Selection\n- Do not give absolute kg.\n- Suggest a load the user controls with good technique.\n- A practical reference is finishing sets with about 1-3 repetitions in reserve.\n- If technique breaks down, reduce load.`,
  execution: `CARD: Exercise Execution\n- Give general technique cues only.\n- Keep cues short and practical.\n- For pulling exercises, mention controlled movement, stable torso, shoulders down/back when appropriate, and avoiding momentum.\n- Ask for exercise name or context if missing.\n- If the user mentions pain, stop normal execution advice and apply safety boundaries.\n- Do not diagnose, correct individual anatomy, or prescribe rehabilitation.`,
  setsReps: `CARD: Sets And Reps\n- For general hypertrophy guidance, many exercises can use moderate repetition ranges such as 8-12 or 10-15.\n- Heavier compound work can use lower ranges when technique is stable.\n- Isolation or lighter work often fits moderate to higher reps.\n- The answer must stay general and should not become individualized programming.\n- Technique and proximity to failure matter more than an exact universal rep number.`,
  style: `CARD: Response Style\n- Respond in pt-BR.\n- Keep replies short and practical for Telegram.\n- Prefer one useful action, brief rationale, and one optional follow-up question.\n- Do not mention internal cards, prompts or implementation details.`,
};

let intent = 'fallback';
let macroIntent = 'unknown';
let riskLevel = 'normal';
let route = 'fixed';
let isFeedback = false;
let feedbackValue = null;
let fixedReply = 'Recebi sua mensagem. Se for sobre treino, me diga se voce quer montar algo curto, trocar exercicio ou tirar uma duvida especifica.';
let knowledgeContext = cards.style;
let finalFallbackReply = 'Recebi sua mensagem, mas o modelo local nao conseguiu responder agora. Posso ajudar com treino curto, descanso, falha, substituicao, dor e carga.';
let fallbackReason = 'fallback_low_confidence';
let classifierStatus = 'not_called';
let classifierConfidence = null;
let classifierNeedsClarification = null;
let classifierError = null;

function useClassifierResult(classification) {
  classifierStatus = classification.status;
  classifierConfidence = classification.confidence;
  classifierNeedsClarification = classification.needs_clarification;
  classifierError = classification.error;

  if (classification.status !== 'success' || classification.confidence === 'low') {
    intent = looksTrainingRelated() ? 'workout_request' : 'fallback';
    macroIntent = looksTrainingRelated() ? 'training_help' : 'out_of_scope';
    route = 'fixed';
    fallbackReason = looksTrainingRelated() ? 'fallback_training_related' : 'fallback_low_confidence';
    fixedReply = looksTrainingRelated()
      ? 'Entendi que e sobre treino. Para eu te ajudar melhor, escolha um caminho: treino curto, trocar exercicio, duvida de execucao, descanso, falha ou carga.'
      : 'Posso ajudar melhor com temas de treino: treino curto, troca de exercicio, execucao, descanso, falha, carga ou dor durante exercicio.';
    return;
  }

  intent = classification.intent;
  macroIntent = classification.macro_intent;
  riskLevel = classification.risk_level;

  if (intent === 'exact_load') {
    route = 'fixed';
    fallbackReason = 'mandatory_load_boundary';
    fixedReply = 'Nao vou indicar kg exato sem avaliar tecnica e contexto. Use uma carga que voce controle bem e termine a serie com cerca de 1 a 3 repeticoes em reserva. Se a tecnica quebrar, reduza.';
  } else if (intent === 'personalized_workout_request') {
    route = 'fixed';
    fallbackReason = 'mandatory_personalization_boundary';
    fixedReply = 'Posso ajudar com uma estrutura geral, mas nao vou fingir personalizacao profunda sem avaliacao. Para ajustar melhor, me diga so 2 coisas: objetivo principal e equipamentos disponiveis.';
  } else if (intent === 'exercise_execution') {
    route = 'local_llm';
    knowledgeContext = `${cards.execution}\n\n${cards.style}`;
    finalFallbackReply = 'Consigo ajudar com orientacao geral de execucao. Mantenha o movimento controlado, sem impulso, e me diga o exercicio se quiser uma dica mais especifica.';
    fixedReply = null;
    fallbackReason = 'classified_execution_local_llm_fallback';
  } else if (intent === 'training_variable_question') {
    route = 'local_llm';
    knowledgeContext = `${cards.setsReps}\n\n${cards.failure}\n\n${cards.style}`;
    finalFallbackReply = 'Como guia geral, muitos exercicios funcionam bem em faixas como 8-12 ou 10-15 repeticoes, mantendo tecnica boa e algumas repeticoes em reserva. O ideal depende do exercicio e do objetivo da sessao.';
    fixedReply = null;
    fallbackReason = 'classified_training_variable_local_llm_fallback';
  } else if (intent === 'concept_explanation') {
    route = 'local_llm';
    knowledgeContext = `${cards.setsReps}\n\n${cards.failure}\n\n${cards.rest}\n\n${cards.style}`;
    finalFallbackReply = 'Posso explicar de forma geral. Me diga se sua duvida e sobre series, repeticoes, descanso, carga, falha ou execucao.';
    fixedReply = null;
    fallbackReason = 'classified_concept_local_llm_fallback';
  } else if (intent === 'workout_request') {
    route = 'fixed';
    fallbackReason = 'needs_session_context';
    fixedReply = 'Consigo montar uma ideia geral, sem fingir personalizacao profunda. Me diga so 2 coisas: quanto tempo voce tem hoje e quais equipamentos estao disponiveis.';
  } else if (intent === 'substitution') {
    route = 'local_llm';
    knowledgeContext = `${cards.substitution}\n\n${cards.style}`;
    finalFallbackReply = 'Pode fazer sentido trocar, mas exercicios parecidos nao sao identicos. Me diga qual exercicio voce quer trocar e o motivo: equipamento, preferencia, dificuldade, tempo ou dor.';
    fixedReply = null;
    fallbackReason = 'classified_substitution_local_llm_fallback';
  } else if (intent === 'short_workout') {
    route = 'local_llm';
    knowledgeContext = `${cards.shortWorkout}\n\n${cards.load}\n\n${cards.style}`;
    finalFallbackReply = 'Ideia geral de treino curto:\n\n1. Aquecimento: 5 min leve.\n2. Leg press: 3x8-12.\n3. Supino ou flexao: 3x8-12.\n4. Remada: 3x8-12.\n5. Mesa flexora: 2x10-12.\n6. Prancha: 2x30-45s.\n\nUse carga controlavel e pare se sentir dor fora do normal.';
    fixedReply = null;
    fallbackReason = 'classified_short_workout_local_llm_fallback';
  } else if (intent === 'rest_question') {
    route = 'local_llm';
    knowledgeContext = `${cards.rest}\n\n${cards.style}`;
    finalFallbackReply = 'Como regra geral: 1-2 min funciona bem para exercicios leves ou isoladores; 2-3 min costuma ajudar em exercicios pesados como agachamento, supino e remada. Se a tecnica cair muito, descanse mais.';
    fixedReply = null;
    fallbackReason = 'classified_rest_local_llm_fallback';
  } else if (intent === 'failure_question') {
    route = 'local_llm';
    knowledgeContext = `${cards.failure}\n\n${cards.style}`;
    finalFallbackReply = 'Nao precisa ir ate a falha em toda serie. Uma boa referencia e terminar muitas series com 1 a 3 repeticoes em reserva. Falha pode ser util em alguns momentos, mas aumenta fadiga e risco de perder tecnica.';
    fixedReply = null;
    fallbackReason = 'classified_failure_local_llm_fallback';
  } else if (intent === 'out_of_scope') {
    route = 'fixed';
    fallbackReason = 'fallback_out_of_scope';
    fixedReply = 'Posso ajudar melhor com temas de treino: treino curto, troca de exercicio, execucao, descanso, falha, carga ou dor durante exercicio.';
  } else {
    route = 'fixed';
    fallbackReason = 'fallback_training_related';
    fixedReply = 'Entendi que e sobre treino. Para eu te ajudar melhor, escolha um caminho: treino curto, trocar exercicio, duvida de execucao, descanso, falha ou carga.';
  }
}

const positiveFeedback = new Set(['sim', 'ajudou', 'ok', 'boa', 'positivo']);
const negativeFeedback = new Set(['nao', 'nao ajudou', 'ruim', 'negativo']);

if (!text) {
  intent = 'non_text';
  macroIntent = 'unsupported_format';
  route = 'fixed';
  fallbackReason = 'fallback_unsupported_format';
  fixedReply = 'Por enquanto eu so consigo responder mensagens de texto. Me diga sua duvida ou o treino que voce quer ajustar.';
} else if (positiveFeedback.has(normalized)) {
  intent = 'feedback';
  macroIntent = 'meta_or_feedback';
  route = 'fixed';
  isFeedback = true;
  feedbackValue = 'positive';
  fallbackReason = 'rule_based_feedback';
  fixedReply = 'Valeu pelo feedback. Vou manter respostas curtas e praticas por aqui.';
} else if (negativeFeedback.has(normalized)) {
  intent = 'feedback';
  macroIntent = 'meta_or_feedback';
  route = 'fixed';
  isFeedback = true;
  feedbackValue = 'negative';
  fallbackReason = 'rule_based_feedback';
  fixedReply = 'Obrigado pelo feedback. Me diga em uma frase o que faltou ou o que voce queria ajustar.';
} else if (hasRiskSignal()) {
  intent = 'discomfort';
  macroIntent = 'risk_signal';
  route = 'fixed';
  riskLevel = hasStopRiskSignal() ? 'stop' : 'caution';
  fallbackReason = 'mandatory_safety_response';
  fixedReply = riskLevel === 'stop'
    ? 'Para agora e evite repetir o movimento que causou isso. Nao consigo diagnosticar pelo chat. Se a dor foi forte, aguda, esta piorando, teve formigamento, tontura ou dor no peito, procure avaliacao profissional ou atendimento urgente.'
    : 'Se apareceu dor ou desconforto, reduza ou pare o movimento por enquanto. Nao treine atravessando dor. Se persistir ou piorar, procure avaliacao profissional. Posso sugerir uma alternativa geral mais conservadora se voce me disser o exercicio.';
} else if (hasAny(['quantos kg', 'quanto peso', 'carga exata', 'qual carga', 'kg eu coloco'])) {
  intent = 'exact_load';
  macroIntent = 'training_variable';
  route = 'fixed';
  fallbackReason = 'mandatory_load_boundary';
  fixedReply = 'Nao vou indicar kg exato sem avaliar tecnica e contexto. Use uma carga que voce controle bem e termine a serie com cerca de 1 a 3 repeticoes em reserva. Se a tecnica quebrar, reduza.';
} else if (hasAny(['lembra', 'ontem', 'treino anterior', 'ultima vez', 'semana passada'])) {
  intent = 'memory_request';
  macroIntent = 'meta_or_feedback';
  route = 'fixed';
  fallbackReason = 'mandatory_no_memory_boundary';
  fixedReply = 'Neste MVP eu nao lembro sessoes anteriores. Me reenvie o treino ou diga o objetivo de hoje que eu te ajudo a partir da mensagem atual.';
} else if (isStartCommand() || isGreetingOnly() || hasAny(['comecar', 'inicio'])) {
  intent = 'onboarding';
  macroIntent = 'meta_or_feedback';
  route = 'fixed';
  fallbackReason = 'rule_based_onboarding';
  fixedReply = 'Oi. Eu sou o Gym Buddy. Posso ajudar com duvidas rapidas de treino, descanso, falha, substituicoes e ideias gerais de treino curto. Nao precisa usar /start: me diga direto o que voce precisa agora.';
} else if (hasAny(['treino rapido', 'treino de 30', '30 min', '30 minutos', 'meia hora', '20 min', '20 minutos', 'pouco tempo'])) {
  intent = 'short_workout';
  macroIntent = 'workout_structure';
  knowledgeContext = `${cards.shortWorkout}\n\n${cards.load}\n\n${cards.style}`;
  finalFallbackReply = 'Ideia geral de treino curto:\n\n1. Aquecimento: 5 min leve.\n2. Leg press: 3x8-12.\n3. Supino ou flexao: 3x8-12.\n4. Remada: 3x8-12.\n5. Mesa flexora: 2x10-12.\n6. Prancha: 2x30-45s.\n\nUse carga controlavel e pare se sentir dor fora do normal.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['descanso', 'descansar', 'intervalo'])) {
  intent = 'rest_question';
  macroIntent = 'training_variable';
  knowledgeContext = `${cards.rest}\n\n${cards.style}`;
  finalFallbackReply = 'Como regra geral: 1-2 min funciona bem para exercicios leves ou isoladores; 2-3 min costuma ajudar em exercicios pesados como agachamento, supino e remada. Se a tecnica cair muito, descanse mais.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['falha', 'ate a falha', 'rir', 'repeticoes em reserva'])) {
  intent = 'failure_question';
  macroIntent = 'training_variable';
  knowledgeContext = `${cards.failure}\n\n${cards.style}`;
  finalFallbackReply = 'Nao precisa ir ate a falha em toda serie. Uma boa referencia e terminar muitas series com 1 a 3 repeticoes em reserva. Falha pode ser util em alguns momentos, mas aumenta fadiga e risco de perder tecnica.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['trocar', 'troca', 'mudar', 'muda', 'substituir', 'substituicao', 'no lugar de', 'alternativa', 'adaptar'])) {
  intent = 'substitution';
  macroIntent = 'exercise_change';
  knowledgeContext = `${cards.substitution}\n\n${cards.style}`;
  finalFallbackReply = 'Pode fazer sentido trocar, mas exercicios parecidos nao sao identicos. Me diga qual exercicio voce quer trocar e o motivo: equipamento, preferencia, dificuldade, tempo ou dor.';
  route = 'local_llm';
  fixedReply = null;
  fallbackReason = 'primary_llm_disabled_local_llm_fallback';
} else if (hasAny(['personalizado', 'personalizada', 'pra mim', 'para mim'])) {
  intent = 'personalized_workout_request';
  macroIntent = 'workout_structure';
  route = 'fixed';
  fallbackReason = 'mandatory_personalization_boundary';
  fixedReply = 'Posso ajudar com uma estrutura geral, mas nao vou fingir personalizacao profunda sem avaliacao. Para ajustar melhor, me diga so 2 coisas: objetivo principal e equipamentos disponiveis.';
} else if (looksExecutionQuestion()) {
  intent = 'exercise_execution';
  macroIntent = 'exercise_execution';
  route = 'local_llm';
  knowledgeContext = `${cards.execution}\n\n${cards.style}`;
  finalFallbackReply = 'Consigo ajudar com orientacao geral de execucao. Mantenha o movimento controlado, sem impulso, e me diga o exercicio se quiser uma dica mais especifica.';
  fixedReply = null;
  fallbackReason = 'rule_execution_local_llm_fallback';
} else if (looksWorkoutStructureRequest()) {
  intent = 'workout_request';
  macroIntent = 'workout_structure';
  route = 'fixed';
  fallbackReason = 'needs_session_context';
  fixedReply = 'Consigo montar uma ideia geral, sem fingir personalizacao profunda. Me diga so 2 coisas: quanto tempo voce tem hoje e quais equipamentos estao disponiveis.';
} else if (looksTrainingVariableQuestion()) {
  intent = 'training_variable_question';
  macroIntent = 'training_variable';
  route = 'local_llm';
  knowledgeContext = `${cards.setsReps}\n\n${cards.failure}\n\n${cards.style}`;
  finalFallbackReply = 'Como guia geral, muitos exercicios funcionam bem em faixas como 8-12 ou 10-15 repeticoes, mantendo tecnica boa e algumas repeticoes em reserva. O ideal depende do exercicio e do objetivo da sessao.';
  fixedReply = null;
  fallbackReason = 'rule_training_variable_local_llm_fallback';
} else {
  const classification = await classifyWithLlm();
  useClassifierResult(classification);
}

const requiresLlm = route === 'local_llm';
const systemPrompt = `Voce e o Gym Buddy, um assistente pratico de apoio a treino para Telegram. Responda em pt-BR. Use apenas orientacao geral, curta e segura. Nao diagnostique, nao trate lesao, nao prescreva reabilitacao, nao indique kg exato, nao prometa resultado e nao finja memoria ou personalizacao profunda. Casos de dor ou risco ja foram bloqueados antes de chegar aqui. Use somente nomes comuns de exercicios de academia; nao invente nomes. Nao mencione bastidores, cards ou implementacao.`;
const userPrompt = `Intent: ${intent}\nMacro intent: ${macroIntent}\nRisk level: ${riskLevel}\nContexto curado:\n${knowledgeContext}\n\nMensagem do usuario:\n${text}\n\nGere uma resposta curta e pratica para Telegram.`;

return [{
  json: {
    channel: 'telegram',
    user_id: from.id ?? null,
    chat_id: chat.id ?? null,
    username: from.username ?? null,
    first_name: from.first_name ?? null,
    message_id: message.message_id ?? null,
    message_text: text,
    message_type: text ? 'text' : 'non_text',
    received_at: message.date ? new Date(message.date * 1000).toISOString() : new Date().toISOString(),
    intent,
    macro_intent: macroIntent,
    risk_level: riskLevel,
    route,
    is_feedback: isFeedback,
    feedback_value: feedbackValue,
    requires_llm: requiresLlm,
    fixed_reply: fixedReply,
    final_fallback_reply: finalFallbackReply,
    fallback_reason: fallbackReason,
    knowledge_context: knowledgeContext,
    primary_llm_status: 'disabled_budget',
    classifier_status: classifierStatus,
    classifier_confidence: classifierConfidence,
    classifier_needs_clarification: classifierNeedsClarification,
    classifier_error: classifierError,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

const baseUrl = 'http://ollama:11434';
const model = 'llama3.2:3b';

try {
  const response = await fetch(`${baseUrl}/api/chat`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model,
      stream: false,
      options: {
        temperature: 0.25,
        num_predict: 260
      },
      messages: [
        { role: 'system', content: $json.system_prompt },
        { role: 'user', content: $json.user_prompt }
      ]
    })
  });

  const raw = await response.text();
  let parsed = {};
  try { parsed = raw ? JSON.parse(raw) : {}; } catch (error) { parsed = { raw }; }

  if (!response.ok) {
    return [{ json: { ...$json, error: { provider: 'ollama', code: response.status, message: parsed.error || response.statusText || 'Ollama request failed', raw: parsed } } }];
  }

  return [{ json: { ...$json, llm_provider: 'ollama', llm_model: model, text: parsed.message?.content ?? parsed.response ?? '', raw_ollama_response: parsed } }];
} catch (error) {
  return [{ json: { ...$json, error: { provider: 'ollama', code: error.name || 'OLLAMA_REQUEST_ERROR', message: error.message || 'Ollama request failed' } } }];
}

const source = $('Route And Build Context').first().json;
const errorMessage = $json.error?.message ?? null;
const errorCode = $json.error?.code ?? null;
const provider = $json.error?.provider ?? $json.llm_provider ?? 'ollama';
const hasLlmError = Boolean($json.error || errorCode);
const modelReply = String($json.text ?? '').trim();
const replyText = hasLlmError ? source.final_fallback_reply : (modelReply || source.final_fallback_reply);

return [{
  json: {
    ...source,
    reply_text: replyText,
    handled_at: new Date().toISOString(),
    llm_provider: provider,
    llm_model: $json.llm_model ?? null,
    llm_status: hasLlmError ? 'error' : 'success',
    llm_error_code: errorCode,
    llm_error_message: errorMessage,
    used_final_fallback: hasLlmError || !modelReply
  }
}];
